"use client";

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { 
  User, 
  Mail, 
  Phone, 
  MapPin, 
  Star,
  Calendar,
  Award,
  Edit,
  Camera
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/components/ui/use-toast";

const services = [
  { id: 1, name: "Deep Cleaning", selected: true },
  { id: 2, name: "Standard Cleaning", selected: true },
  { id: 3, name: "Office Cleaning", selected: true },
  { id: 4, name: "Carpet Cleaning", selected: true },
  { id: 5, name: "Move In/Out Cleaning", selected: false },
  { id: 6, name: "Window Cleaning", selected: false },
];

const reviews = [
  {
    id: 1,
    customer: "Sarah Johnson",
    rating: 5,
    comment: "Excellent service! Very thorough and professional.",
    date: "2024-12-05",
    service: "Deep Cleaning"
  },
  {
    id: 2,
    customer: "Mike Davis",
    rating: 5,
    comment: "Great job! Will definitely book again.",
    date: "2024-12-04",
    service: "Standard Cleaning"
  },
  {
    id: 3,
    customer: "Emily Chen",
    rating: 4,
    comment: "Good work, arrived on time and did a thorough job.",
    date: "2024-12-03",
    service: "Office Cleaning"
  },
  {
    id: 4,
    customer: "Robert Wilson",
    rating: 5,
    comment: "Outstanding! My carpets look brand new.",
    date: "2024-12-02",
    service: "Carpet Cleaning"
  },
];

const ProviderProfile = () => {
  const [isEditing, setIsEditing] = useState(false);
  const [providerName, setProviderName] = useState("John Smith");
  const [email, setEmail] = useState("provider@orbitbooking.com");
  const [phone, setPhone] = useState("(555) 123-4567");
  const [location, setLocation] = useState("New York, NY");
  const [bio, setBio] = useState("Professional cleaning service provider with 5+ years of experience. Specialized in residential and commercial cleaning.");
  const { toast } = useToast();

  useEffect(() => {
    const name = localStorage.getItem("providerName");
    const storedEmail = localStorage.getItem("providerEmail");
    if (name) setProviderName(name);
    if (storedEmail) setEmail(storedEmail);
  }, []);

  const handleSaveProfile = () => {
    localStorage.setItem("providerName", providerName);
    toast({
      title: "Profile Updated",
      description: "Your profile has been successfully updated.",
    });
    setIsEditing(false);
  };

  const averageRating = (reviews.reduce((acc, review) => acc + review.rating, 0) / reviews.length).toFixed(1);

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold mb-2">My Profile</h1>
        <p className="text-muted-foreground">Manage your profile and service offerings</p>
      </div>

      {/* Profile Overview */}
      <Card>
        <CardContent className="p-6">
          <div className="flex flex-col md:flex-row gap-6">
            {/* Profile Picture */}
            <div className="flex flex-col items-center gap-3">
              <div className="relative">
                <div className="h-32 w-32 rounded-full bg-gradient-to-br from-cyan-500 to-blue-500 flex items-center justify-center text-white text-4xl font-bold">
                  {providerName.charAt(0)}
                </div>
                <button className="absolute bottom-0 right-0 h-10 w-10 rounded-full bg-primary text-primary-foreground flex items-center justify-center hover:bg-primary/90 transition-colors">
                  <Camera className="h-5 w-5" />
                </button>
              </div>
              <div className="text-center">
                <div className="flex items-center gap-1 justify-center mb-1">
                  <Star className="h-5 w-5 fill-orange-400 text-orange-400" />
                  <span className="font-bold text-lg">{averageRating}</span>
                </div>
                <p className="text-sm text-muted-foreground">{reviews.length} reviews</p>
              </div>
            </div>

            {/* Profile Info */}
            <div className="flex-1 space-y-4">
              {isEditing ? (
                <>
                  <div>
                    <label className="text-sm font-medium mb-1 block">Full Name</label>
                    <Input
                      value={providerName}
                      onChange={(e) => setProviderName(e.target.value)}
                    />
                  </div>
                  <div className="grid md:grid-cols-2 gap-4">
                    <div>
                      <label className="text-sm font-medium mb-1 block">Email</label>
                      <Input
                        type="email"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                      />
                    </div>
                    <div>
                      <label className="text-sm font-medium mb-1 block">Phone</label>
                      <Input
                        value={phone}
                        onChange={(e) => setPhone(e.target.value)}
                      />
                    </div>
                  </div>
                  <div>
                    <label className="text-sm font-medium mb-1 block">Location</label>
                    <Input
                      value={location}
                      onChange={(e) => setLocation(e.target.value)}
                    />
                  </div>
                  <div>
                    <label className="text-sm font-medium mb-1 block">Bio</label>
                    <Textarea
                      value={bio}
                      onChange={(e) => setBio(e.target.value)}
                      rows={3}
                    />
                  </div>
                  <div className="flex gap-2">
                    <Button onClick={handleSaveProfile} style={{ background: 'linear-gradient(135deg, #00BCD4 0%, #00D4E8 100%)', color: 'white' }}>
                      Save Changes
                    </Button>
                    <Button variant="outline" onClick={() => setIsEditing(false)}>
                      Cancel
                    </Button>
                  </div>
                </>
              ) : (
                <>
                  <div>
                    <h2 className="text-2xl font-bold mb-2">{providerName}</h2>
                    <p className="text-muted-foreground">{bio}</p>
                  </div>
                  <div className="grid md:grid-cols-2 gap-3">
                    <div className="flex items-center gap-2 text-sm">
                      <Mail className="h-4 w-4 text-muted-foreground" />
                      <span>{email}</span>
                    </div>
                    <div className="flex items-center gap-2 text-sm">
                      <Phone className="h-4 w-4 text-muted-foreground" />
                      <span>{phone}</span>
                    </div>
                    <div className="flex items-center gap-2 text-sm">
                      <MapPin className="h-4 w-4 text-muted-foreground" />
                      <span>{location}</span>
                    </div>
                    <div className="flex items-center gap-2 text-sm">
                      <Calendar className="h-4 w-4 text-muted-foreground" />
                      <span>Member since Nov 2024</span>
                    </div>
                  </div>
                  <Button onClick={() => setIsEditing(true)} variant="outline">
                    <Edit className="h-4 w-4 mr-2" />
                    Edit Profile
                  </Button>
                </>
              )}
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Stats */}
      <div className="grid gap-4 md:grid-cols-4">
        <Card>
          <CardContent className="p-6 text-center">
            <div className="h-12 w-12 rounded-full bg-green-100 dark:bg-green-900/20 flex items-center justify-center mx-auto mb-3">
              <Award className="h-6 w-6 text-green-600" />
            </div>
            <p className="text-2xl font-bold mb-1">28</p>
            <p className="text-sm text-muted-foreground">Completed Jobs</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-6 text-center">
            <div className="h-12 w-12 rounded-full bg-orange-100 dark:bg-orange-900/20 flex items-center justify-center mx-auto mb-3">
              <Star className="h-6 w-6 text-orange-600" />
            </div>
            <p className="text-2xl font-bold mb-1">{averageRating}</p>
            <p className="text-sm text-muted-foreground">Average Rating</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-6 text-center">
            <div className="h-12 w-12 rounded-full bg-blue-100 dark:bg-blue-900/20 flex items-center justify-center mx-auto mb-3">
              <User className="h-6 w-6 text-blue-600" />
            </div>
            <p className="text-2xl font-bold mb-1">24</p>
            <p className="text-sm text-muted-foreground">Happy Customers</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-6 text-center">
            <div className="h-12 w-12 rounded-full bg-cyan-100 dark:bg-cyan-900/20 flex items-center justify-center mx-auto mb-3">
              <Calendar className="h-6 w-6 text-cyan-600" />
            </div>
            <p className="text-2xl font-bold mb-1">5+</p>
            <p className="text-sm text-muted-foreground">Years Experience</p>
          </CardContent>
        </Card>
      </div>

      {/* Services Offered */}
      <Card>
        <CardHeader>
          <CardTitle>Services Offered</CardTitle>
          <p className="text-sm text-muted-foreground mt-1">
            Select the services you provide
          </p>
        </CardHeader>
        <CardContent>
          <div className="grid gap-3 md:grid-cols-3">
            {services.map((service) => (
              <div
                key={service.id}
                className={`
                  p-4 rounded-lg border-2 cursor-pointer transition-all
                  ${service.selected 
                    ? 'border-cyan-500 bg-cyan-50 dark:bg-cyan-900/20' 
                    : 'border-border hover:border-muted-foreground'
                  }
                `}
              >
                <div className="flex items-center justify-between">
                  <span className="font-medium">{service.name}</span>
                  {service.selected && (
                    <div className="h-5 w-5 rounded-full bg-cyan-500 flex items-center justify-center">
                      <svg className="h-3 w-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                      </svg>
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Reviews */}
      <Card>
        <CardHeader>
          <CardTitle>Customer Reviews</CardTitle>
          <p className="text-sm text-muted-foreground mt-1">
            What customers are saying about you
          </p>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {reviews.map((review) => (
              <div key={review.id} className="p-4 rounded-lg border border-border">
                <div className="flex items-start justify-between mb-2">
                  <div className="flex items-center gap-3">
                    <div className="h-10 w-10 rounded-full bg-gradient-to-br from-cyan-500 to-blue-500 flex items-center justify-center text-white font-semibold">
                      {review.customer.charAt(0)}
                    </div>
                    <div>
                      <p className="font-semibold">{review.customer}</p>
                      <p className="text-xs text-muted-foreground">{review.service}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-1">
                    {Array.from({ length: review.rating }).map((_, i) => (
                      <Star key={i} className="h-4 w-4 fill-orange-400 text-orange-400" />
                    ))}
                  </div>
                </div>
                <p className="text-sm text-muted-foreground mb-2">{review.comment}</p>
                <p className="text-xs text-muted-foreground">{review.date}</p>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
};

export default ProviderProfile;
